import{c as s,cG as a,cb as n,c8 as e,cf as t,cT as l,ce as i}from"./chunks/framework.BlkIsu1j.js";const p=JSON.parse('{"title":"第 11 章：上下文管理","description":"","frontmatter":{"title":"第 11 章：上下文管理","outline":"deep","layout":"doc","prev":"/ai/claudecodenew/10-how-it-works","next":"/ai/claudecodenew/12-claude-md","date":"2026-05-30T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecodenew/11-context-management.md","filePath":"ai/claudecodenew/11-context-management.md","lastUpdated":1780121796000}'),o={id:"frontmatter-title",tabindex:"-1"};const r=s({name:"ai/claudecodenew/11-context-management.md"},[["render",function(s,p,r,d,c,h){return a(),n("div",null,[e("h1",o,[t(l(s.$frontmatter.title)+" ",1),p[0]||(p[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),p[1]||(p[1]=i('<p>第 10 章我们拆解了 Claude Code 的 Agent Loop 和工具系统——你知道了 Claude <strong>怎么工作</strong>。这一章我们要解决一个直接影响工作质量的核心问题：Claude <strong>记得什么</strong>、<strong>记得多少</strong>、以及<strong>忘了怎么办</strong>。</p><p>上下文管理是区分&quot;会用 Claude Code&quot;和&quot;用好 Claude Code&quot;的分水岭。同样的指令，为什么有时 Claude 给出精准优雅的方案，有时却答非所问？同样的 Bug，为什么有时一次定位成功，有时绕了三圈还在原地打转？答案往往不在于你的指令质量，而在于<strong>上下文的状态</strong>。</p><blockquote><p><strong>本章目标</strong>：理解上下文窗口的概念和构成，识别上下文膨胀的症状，掌握 <code>/compact</code> 和 <code>/clear</code> 的使用时机与技巧，建立多会话管理的工作习惯。</p></blockquote><h2 id="_11-1-什么是上下文窗口" tabindex="-1">11.1 什么是上下文窗口 <a class="header-anchor" href="#_11-1-什么是上下文窗口" aria-label="Permalink to “11.1 什么是上下文窗口”">​</a></h2><h3 id="类比-ai-的-工作记忆" tabindex="-1">类比：AI 的&quot;工作记忆&quot; <a class="header-anchor" href="#类比-ai-的-工作记忆" aria-label="Permalink to “类比：AI 的&quot;工作记忆&quot;”">​</a></h3><p>把 Claude 想象成一位坐在你旁边编程的同事。他面前的桌子上摊着几样东西：</p><ul><li>一本<strong>行为守则</strong>（系统提示词），告诉他什么能做、什么不能做</li><li>一份<strong>项目说明书</strong>（CLAUDE.md），记录了项目结构、技术栈和约定</li><li>你们的<strong>对话记录</strong>（聊天历史），从第一句话到现在</li><li>他刚<strong>翻阅过的文件</strong>（Read 工具的输出）</li><li>他执行命令后的<strong>终端输出</strong>（Bash 工具的结果）</li></ul><p>这张桌子的面积是<strong>有限的</strong>——当东西太多时，他必须把一些纸张收起来，腾出空间放新的。这个&quot;桌面面积&quot;就是<strong>上下文窗口</strong>（Context Window）。</p><p>在技术层面，上下文窗口是模型在一次推理中能够&quot;看见&quot;的最大 token 数量。窗口内的所有内容构成了模型做决策的<strong>全部信息基础</strong>——窗口之外的世界对模型来说完全不可见。</p><h3 id="什么是-token" tabindex="-1">什么是 Token <a class="header-anchor" href="#什么是-token" aria-label="Permalink to “什么是 Token”">​</a></h3><p>Token 是模型处理文本的最小单位。它不是字符，也不是单词，而是介于两者之间的&quot;语义片段&quot;。</p><p><strong>英文的 Token 划分</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;Claude Code is an AI coding tool.&quot;</span></span>\n<span class="line"><span> → [&quot;Claude&quot;, &quot; Code&quot;, &quot; is&quot;, &quot; an&quot;, &quot; AI&quot;, &quot; coding&quot;, &quot; tool&quot;, &quot;.&quot;]</span></span>\n<span class="line"><span> → 8 tokens</span></span></code></pre></div><p>英文大致是 <strong>1 token ≈ 0.75 个单词</strong>，或者说 1 个单词 ≈ 1.3 个 token。</p><p><strong>中文的 Token 划分</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;Claude Code 是一个 AI 编程工具。&quot;</span></span>\n<span class="line"><span> → [&quot;Claude&quot;, &quot; Code&quot;, &quot; 是&quot;, &quot;一个&quot;, &quot; AI&quot;, &quot; 编程&quot;, &quot;工具&quot;, &quot;。&quot;]</span></span>\n<span class="line"><span> → 8 tokens</span></span></code></pre></div><p>中文的一个汉字通常占 1-2 个 token（取决于编码方式和上下文），大致 <strong>1 个汉字 ≈ 1.5 token</strong>。换句话说，<strong>同样的语义内容，中文消耗的 token 通常是英文的 1.5-2 倍</strong>。</p><blockquote><p>这意味着：用中文与 Claude Code 对话时，你的上下文窗口会被更快地填满。这是一个容易被忽视但影响深远的差异。</p></blockquote><h3 id="各模型的上下文窗口" tabindex="-1">各模型的上下文窗口 <a class="header-anchor" href="#各模型的上下文窗口" aria-label="Permalink to “各模型的上下文窗口”">​</a></h3><p>不同模型的&quot;桌面面积&quot;差异巨大：</p><table tabindex="0"><thead><tr><th>模型</th><th>上下文窗口</th><th>等效页面数（估算）</th><th>备注</th></tr></thead><tbody><tr><td><strong>Claude Opus 4.7</strong></td><td>200K tokens</td><td>~600 页</td><td>Anthropic 旗舰，推理最强</td></tr><tr><td><strong>Claude Sonnet 4.6</strong></td><td>200K tokens</td><td>~600 页</td><td>平衡性能与速度</td></tr><tr><td><strong>Claude Haiku 4.5</strong></td><td>200K tokens</td><td>~600 页</td><td>最快响应</td></tr><tr><td><strong>DeepSeek V4 Flash</strong></td><td>1M tokens</td><td>~3,000 页</td><td>极低成本 + 超大窗口</td></tr><tr><td><strong>DeepSeek V4 Pro</strong></td><td>1M tokens</td><td>~3,000 页</td><td>强推理 + 超大窗口</td></tr></tbody></table><blockquote><p>1M tokens 是什么概念？大约可以容纳《三体》三部曲的全部文本，还有余量。DeepSeek V4 的 1M 上下文窗口意味着——你几乎不会因为对话太长而遇到上下文溢出。</p></blockquote><p>但别高兴太早。上下文窗口大 ≠ 模型能有效利用全部窗口。研究表明，模型对<strong>窗口中间位置</strong>的信息利用效率低于开头和结尾（即&quot;Lost in the Middle&quot;现象）。所以即使有 1M 窗口，你仍需要管理好上下文。</p><h3 id="上下文预算的可视化" tabindex="-1">上下文预算的可视化 <a class="header-anchor" href="#上下文预算的可视化" aria-label="Permalink to “上下文预算的可视化”">​</a></h3><p>想象一个逐渐被填满的进度条。这是一个典型对话的上下文消耗过程：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>上下文预算（200K tokens）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>对话开始:</span></span>\n<span class="line"><span>[System Prompt ████░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░] ~8K (4%)</span></span>\n<span class="line"><span>加入 CLAUDE.md:</span></span>\n<span class="line"><span>[System ████|CLAUDE.md ██░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░░] ~12K (6%)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第 1 轮对话 + 读取 3 个文件:</span></span>\n<span class="line"><span>[System ████|CLAUDE.md ██|对话 ██|文件 ███████░░░░░░░░░░░░] ~30K (15%)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第 5 轮对话 + 执行命令 + 输出:</span></span>\n<span class="line"><span>[System ████|CLAUDE.md ██|对话 █████|文件 ███████|命令 ████░] ~65K (33%)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第 15 轮对话 + 多次工具调用:</span></span>\n<span class="line"><span>[System ████|CLAUDE.md ██|对话 ██████████|文件 ████████|工具 ██████░░] ~120K (60%)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第 30 轮对话 + 复杂任务上下文:</span></span>\n<span class="line"><span>[System ████|CLAUDE.md ██|对话 ██████████████|文件 ████████|工具 █████████░] ~170K (85%)</span></span>\n<span class="line"><span>                                                                  ↑</span></span>\n<span class="line"><span>                                                自动压缩触发点（约 85-90%）</span></span></code></pre></div><p>当上下文使用率超过 85% 时，Claude Code 会触发自动压缩（auto-compact）。如果继续增长到接近 100%，模型的行为质量将显著下降——这就是下一节要讨论的问题。</p><h2 id="_11-2-上下文的构成" tabindex="-1">11.2 上下文的构成 <a class="header-anchor" href="#_11-2-上下文的构成" aria-label="Permalink to “11.2 上下文的构成”">​</a></h2><p>在任何一个时刻，Claude Code 的上下文窗口由以下几个部分组成。理解每一部分的性质和大小，是做好上下文管理的前提。</p><h3 id="system-prompt-系统提示词" tabindex="-1">System Prompt（系统提示词） <a class="header-anchor" href="#system-prompt-系统提示词" aria-label="Permalink to “System Prompt（系统提示词）”">​</a></h3><p><strong>大小</strong>：约 5-8K tokens（固定，不可修改）</p><p>系统提示词是 Claude Code 的&quot;出厂设定&quot;。它在每次对话启动时自动加载，包含：</p><ul><li><strong>行为准则</strong>：安全性约束、编码风格偏好、响应格式要求</li><li><strong>工具定义</strong>：所有可用工具的 JSON Schema（名称、参数、返回值格式）</li><li><strong>平台信息</strong>：操作系统类型、Shell 环境、当前工作目录</li><li><strong>Git 状态快照</strong>：当前分支、未提交变更、最近提交记录</li></ul><p>你无法直接修改系统提示词，但它的内容会占用固定的上下文配额。这是你的&quot;固定开销&quot;——什么都不做就已经消耗了 ~6K tokens。</p><h3 id="claude-md-项目上下文" tabindex="-1">CLAUDE.md（项目上下文） <a class="header-anchor" href="#claude-md-项目上下文" aria-label="Permalink to “CLAUDE.md（项目上下文）”">​</a></h3><p><strong>大小</strong>：0-5K tokens（可变，由你控制）</p><p>项目根目录的 <code>CLAUDE.md</code> 在每次对话启动时被自动读取。它的大小<strong>完全取决于你写了多少</strong>。一个精炼的 CLAUDE.md（200-500 字）仅占 ~1K tokens，而一个详尽的项目文档可能占 5-10K tokens。</p><p>在第 12 章中，我们将深入讨论如何编写高效的 CLAUDE.md——核心原则是：<strong>信息密度高，废话少</strong>。</p><h3 id="对话历史-conversation-history" tabindex="-1">对话历史（Conversation History） <a class="header-anchor" href="#对话历史-conversation-history" aria-label="Permalink to “对话历史（Conversation History）”">​</a></h3><p><strong>大小</strong>：从 0 开始，持续增长（无上限，直到触发压缩）</p><p>这是上下文窗口中<strong>增长最快、最不可控</strong>的部分。每一条消息、每一次工具调用、每一个工具返回结果，都会追加到对话历史中。</p><p>一个典型的消息-回复对消耗的 token 量：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户消息（中文，50 字）:                    ~100 tokens</span></span>\n<span class="line"><span>Claude 的思考过程（Thinking）:              ~200-500 tokens</span></span>\n<span class="line"><span>Claude 的文本回复（中文，200 字）:           ~400 tokens</span></span>\n<span class="line"><span>工具调用请求（JSON）:                       ~50-100 tokens</span></span>\n<span class="line"><span>工具返回结果（如文件内容、命令输出）:         ~500-5000 tokens</span></span>\n<span class="line"><span>─────────────────────────────────────────────────</span></span>\n<span class="line"><span>单轮对话总消耗:                             ~1,250-6,100 tokens</span></span></code></pre></div><p>你每进行一轮对话，上下文就膨胀几千 token。30 轮对话后，光对话历史就轻松超过 100K tokens。</p><h3 id="文件内容-file-contents" tabindex="-1">文件内容（File Contents） <a class="header-anchor" href="#文件内容-file-contents" aria-label="Permalink to “文件内容（File Contents）”">​</a></h3><p><strong>大小</strong>：每次 Read 操作几百到几万 tokens（按需加载，累积消耗）</p><p>当 Claude 使用 Read 工具读取一个文件时，该文件的完整内容会进入上下文窗口。一个 500 行的 TypeScript 文件大约占 3-5K tokens。如果 Claude 在一轮对话中读取了 5 个文件，那就是 15-25K tokens。</p><p>需要注意的是：<strong>读取的文件内容会一直保留在上下文中</strong>，即使 Claude 已经完成了对那个文件的操作。除非被压缩清除，否则这些内容会持续占用窗口。</p><h3 id="工具输出-tool-outputs" tabindex="-1">工具输出（Tool Outputs） <a class="header-anchor" href="#工具输出-tool-outputs" aria-label="Permalink to “工具输出（Tool Outputs）”">​</a></h3><p><strong>大小</strong>：因操作而异（从几十到几万 tokens）</p><p>Bash 命令的输出是最不可预测的部分。一个 <code>npm install</code> 的输出可能是几百行，一个 <code>grep</code> 搜索可能返回几十个匹配结果，一个 <code>git diff</code> 的输出可能涵盖几十个文件。</p><p>这些输出在帮助 Claude 做决策的同时，也在快速消耗上下文预算。</p><h3 id="memory-持久化记忆" tabindex="-1">Memory（持久化记忆） <a class="header-anchor" href="#memory-持久化记忆" aria-label="Permalink to “Memory（持久化记忆）”">​</a></h3><p><strong>大小</strong>：通常 &lt; 1K tokens（存储在磁盘，对话启动时加载）</p><p>Memory 系统在 <code>.claude/projects/&lt;path&gt;/memory/</code> 下存储持久化信息。与对话历史不同，memory 是<strong>跨会话</strong>的——下次打开 Claude Code 时，它仍然记得你的偏好和之前的重要决定。</p><p>Memory 的内容通常包括：</p><ul><li>你的技术背景和编码偏好</li><li>当前项目的工作目标和约定</li><li>你之前纠正过的错误和确认的方向</li></ul><h3 id="上下文构成一览" tabindex="-1">上下文构成一览 <a class="header-anchor" href="#上下文构成一览" aria-label="Permalink to “上下文构成一览”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌──────────────────────────────────────────────────────────┐</span></span>\n<span class="line"><span>│                    上下文窗口 (200K / 1M)                  │</span></span>\n<span class="line"><span>├──────────────────────────────────────────────────────────┤</span></span>\n<span class="line"><span>│  System Prompt (~6K)                           固定开销   │</span></span>\n<span class="line"><span>│  ├─ 行为准则、工具定义、平台信息                           │</span></span>\n<span class="line"><span>│  ├─ Git 状态快照                                         │</span></span>\n<span class="line"><span>├──────────────────────────────────────────────────────────┤</span></span>\n<span class="line"><span>│  CLAUDE.md (~1-5K)                            项目上下文   │</span></span>\n<span class="line"><span>│  ├─ 项目架构、技术栈、常用命令                             │</span></span>\n<span class="line"><span>│  ├─ 编码规范、约定                                       │</span></span>\n<span class="line"><span>├──────────────────────────────────────────────────────────┤</span></span>\n<span class="line"><span>│  Memory (~0.5K)                              持久化记忆    │</span></span>\n<span class="line"><span>│  ├─ 用户偏好、已确认的约定                                │</span></span>\n<span class="line"><span>├──────────────────────────────────────────────────────────┤</span></span>\n<span class="line"><span>│  对话历史 (0 → 150K+)                     动态增长 ⚠️      │</span></span>\n<span class="line"><span>│  ├─ 用户消息 + Claude 回复                                │</span></span>\n<span class="line"><span>│  ├─ 思考过程（Thinking）                                  │</span></span>\n<span class="line"><span>│  ├─ 工具调用请求 + 返回结果                               │</span></span>\n<span class="line"><span>│  ├─ 读取的文件内容                                        │</span></span>\n<span class="line"><span>│  ├─ Bash 命令输出                                         │</span></span>\n<span class="line"><span>│  ├─ WebSearch / WebFetch 结果                             │</span></span>\n<span class="line"><span>├──────────────────────────────────────────────────────────┤</span></span>\n<span class="line"><span>│  剩余可用空间                              Claude 的工作区  │</span></span>\n<span class="line"><span>│  └─ 用于新的推理、文件读取、命令执行                       │</span></span>\n<span class="line"><span>└──────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="_11-3-上下文膨胀问题" tabindex="-1">11.3 上下文膨胀问题 <a class="header-anchor" href="#_11-3-上下文膨胀问题" aria-label="Permalink to “11.3 上下文膨胀问题”">​</a></h2><h3 id="问题的本质" tabindex="-1">问题的本质 <a class="header-anchor" href="#问题的本质" aria-label="Permalink to “问题的本质”">​</a></h3><p>上下文窗口就像你的电脑内存——足够大时一切流畅，接近满载时开始卡顿，溢出时直接崩溃。但上下文窗口的问题比内存更微妙：<strong>它不会直接报错，而是让 Claude 的行为质量悄悄下降</strong>。</p><p>随着对话的进行，上下文窗口被不断填充。当剩余空间不足时，模型的信息处理能力开始衰减：</p><ol><li><strong>早期信息被&quot;挤出&quot;注意力范围</strong>：模型对窗口开头的信息关注度下降</li><li><strong>中间信息被弱化</strong>：Lost in the Middle 效应——窗口中间位置的内容更容易被模型忽略</li><li><strong>新信息缺乏&quot;消化空间&quot;</strong>：模型没有足够上下文来充分理解新读入的代码</li><li><strong>推理链变短</strong>：复杂的多步推理需要更多上下文来维持逻辑连贯性</li></ol><h3 id="上下文膨胀的症状" tabindex="-1">上下文膨胀的症状 <a class="header-anchor" href="#上下文膨胀的症状" aria-label="Permalink to “上下文膨胀的症状”">​</a></h3><p>以下是需要警惕的信号——当你观察到以下任何一种情况时，说明上下文已经开始膨胀：</p><p><strong>症状一：Claude &quot;忘记&quot;了早期的指令</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你（第 1 轮）: 这次重构遵循函数式风格，避免使用类</span></span>\n<span class="line"><span>...（中间 20 轮对话）</span></span>\n<span class="line"><span>你（第 22 轮）: 这个新模块也用同样的风格写</span></span>\n<span class="line"><span>Claude: 创建了一个 class BasedService { ... }</span></span></code></pre></div><p>Claude 并非故意忽视你的要求，而是你在第一轮说的&quot;函数式风格&quot;已经被挤到了上下文窗口的远端，在模型做第 22 轮决策时无法有效参照。</p><p><strong>症状二：Claude 开始重复自己或绕圈子</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Claude（第 25 轮）: 我建议将 validator.ts 拆分为三个模块...</span></span>\n<span class="line"><span>你: 这个方案我们第 15 轮讨论过，当时决定不拆分，因为会影响 12 个调用方</span></span>\n<span class="line"><span>Claude: 你说得对。那我改为...（提出另一个第 18 轮已经否决过的方案）</span></span></code></pre></div><p>当 Claude 频繁提出你之前已经讨论并否决过的方案时，说明它已经&quot;忘记&quot;了对话中段的内容。</p><p><strong>症状三：Claude 忽略你刚提到的关键细节</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你: 注意，这个 API 的超时时间是 30 秒，不是默认的 10 秒</span></span>\n<span class="line"><span>Claude: 好的。我会设置 10 秒超时...（忽略了你刚说的内容）</span></span></code></pre></div><p>这看起来像 Claude 不听话，实际上是它在处理你的指令时，注意力被上下文中大量的其他信息分散了。</p><p><strong>症状四：工具调用变得越来越不精准</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 对话早期：</span></span>\n<span class="line"><span>Claude: Read src/services/auth.ts（精准，只读需要的一个文件）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># 对话晚期：</span></span>\n<span class="line"><span>Claude: Read src/services/（模糊，试图读取整个目录）</span></span>\n<span class="line"><span>Claude: Bash: grep -r &quot;auth&quot; .（过于宽泛的搜索）</span></span></code></pre></div><p>当 Claude 的工具调用从&quot;手术刀&quot;变成&quot;散弹枪&quot;，这是上下文过载的典型表现——它没有足够的上下文空间来做精准判断，于是退而求其次，用大范围的搜索来弥补。</p><h3 id="何时需要警觉" tabindex="-1">何时需要警觉 <a class="header-anchor" href="#何时需要警觉" aria-label="Permalink to “何时需要警觉”">​</a></h3><p>以下阈值可以作为参考（以 200K 窗口为例）：</p><table tabindex="0"><thead><tr><th>消息轮数</th><th>工具调用次数</th><th>上下文使用率（估算）</th><th>风险等级</th></tr></thead><tbody><tr><td>&lt; 10 轮</td><td>&lt; 20 次</td><td>&lt; 30%</td><td>🟢 正常</td></tr><tr><td>10-20 轮</td><td>20-40 次</td><td>30-55%</td><td>🟡 注意</td></tr><tr><td>20-35 轮</td><td>40-70 次</td><td>55-80%</td><td>🟠 主动管理</td></tr><tr><td>35-50 轮</td><td>70-100 次</td><td>80-95%</td><td>🔴 立即压缩</td></tr><tr><td>&gt; 50 轮</td><td>&gt; 100 次</td><td>&gt; 95%</td><td>⛔ 上下文过载</td></tr></tbody></table><blockquote><p>注意：这些数字是经验估算。实际消耗速度取决于你的文件大小、命令输出长度、以及 Claude 是否开启了思考模式。DeepSeek V4 的 1M 窗口可以让这些阈值乘以 5 倍，但 Lost in the Middle 效应仍然存在——窗口大了不代表你可以无限堆内容。</p></blockquote><h3 id="一个真实场景" tabindex="-1">一个真实场景 <a class="header-anchor" href="#一个真实场景" aria-label="Permalink to “一个真实场景”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>对话开始: &quot;帮我重构 src/services/orderService.ts&quot;</span></span>\n<span class="line"><span>第 1-3 轮: 读取 orderService.ts（2K tokens）和相关文件（8K tokens）</span></span>\n<span class="line"><span>第 4-8 轮: 讨论重构方案，Claude 提出 3 个方案，你选了第 2 个</span></span>\n<span class="line"><span>第 9-15 轮: Claude 逐步重构，每步读取关联文件验证兼容性</span></span>\n<span class="line"><span>第 16-20 轮: 重构过程中发现了另一个模块的 Bug，你让 Claude 顺便修</span></span>\n<span class="line"><span>第 21-25 轮: 修 Bug 涉及 4 个新文件（15K tokens）</span></span>\n<span class="line"><span>第 26-30 轮: 回到重构，但 Claude 开始&quot;忘记&quot;你之前确认的方案细节</span></span>\n<span class="line"><span>第 31 轮: Claude 修改了一个你第 8 轮明确说过不要动的文件</span></span>\n<span class="line"><span>──────────────────────────────────────</span></span>\n<span class="line"><span>此时上下文使用率可能已经超过 85%</span></span>\n<span class="line"><span>→ 如果还不执行 /compact，后续的每次交互质量都会下降</span></span></code></pre></div><p>这个场景的教训是：<strong>当你在一个对话中&quot;顺便&quot;处理了另一个任务时，上下文膨胀的速度远超你的预期</strong>。这也是为什么本章后面要讲&quot;一次一个主题&quot;的原则。</p><h2 id="_11-4-compact-压缩命令" tabindex="-1">11.4 /compact 压缩命令 <a class="header-anchor" href="#_11-4-compact-压缩命令" aria-label="Permalink to “11.4 /compact 压缩命令”">​</a></h2><p><code>/compact</code> 是你对抗上下文膨胀的主要武器。它不解决问题——它解决问题带来的<strong>后果</strong>。</p><h3 id="compact-做了什么" tabindex="-1">/compact 做了什么 <a class="header-anchor" href="#compact-做了什么" aria-label="Permalink to “/compact 做了什么”">​</a></h3><p>当你执行 <code>/compact</code> 时，Claude Code 会：</p><ol><li><strong>分析</strong>当前的完整对话历史</li><li><strong>提取</strong>关键信息：重要的决策、确认的结论、你的显式偏好</li><li><strong>压缩</strong>冗余内容：重复的工具输出、被纠正的错误尝试、中间步骤的详细过程</li><li><strong>生成</strong>一份精炼的对话摘要，替换原有的对话历史</li><li><strong>保留</strong>最近几轮对话（通常 3-5 轮），确保当前工作的连续性</li></ol><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>压缩前（150K tokens）:</span></span>\n<span class="line"><span>┌────────────────────────────────────────────┐</span></span>\n<span class="line"><span>│ [System Prompt] [CLAUDE.md]                │</span></span>\n<span class="line"><span>│ [消息 1] [回复 1] [工具调用 1] [工具输出 1] │</span></span>\n<span class="line"><span>│ [消息 2] [回复 2] [工具调用 2] [工具输出 2] │</span></span>\n<span class="line"><span>│ ...（大量冗余的工具输出和纠正过程）          │</span></span>\n<span class="line"><span>│ [消息 30] [回复 30] [工具调用 30]            │</span></span>\n<span class="line"><span>│ [消息 31] [回复 31]（最近 3 轮保留）          │</span></span>\n<span class="line"><span>└────────────────────────────────────────────┘</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>压缩后（~35K tokens）:</span></span>\n<span class="line"><span>┌────────────────────────────────────────────┐</span></span>\n<span class="line"><span>│ [System Prompt] [CLAUDE.md]                │</span></span>\n<span class="line"><span>│ [压缩摘要]                                  │</span></span>\n<span class="line"><span>│  ├─ 项目：重构 orderService 模块             │</span></span>\n<span class="line"><span>│  ├─ 决定：采用方案 2（策略模式），不动 API 层 │</span></span>\n<span class="line"><span>│  ├─ 用户偏好：函数式风格，避免 class          │</span></span>\n<span class="line"><span>│  ├─ 已完成：orderService.ts 核心逻辑重构      │</span></span>\n<span class="line"><span>│  ├─ 待处理：PaymentGateway 接口兼容性验证     │</span></span>\n<span class="line"><span>│  └─ 注意事项：不要修改 src/api/ 下的文件      │</span></span>\n<span class="line"><span>│ [消息 31] [回复 31]（最近 3 轮保留）          │</span></span>\n<span class="line"><span>└────────────────────────────────────────────┘</span></span></code></pre></div><p>释放了约 115K tokens——足够再进行 15-20 轮高质量对话。</p><h3 id="自动压缩-vs-手动压缩" tabindex="-1">自动压缩 vs 手动压缩 <a class="header-anchor" href="#自动压缩-vs-手动压缩" aria-label="Permalink to “自动压缩 vs 手动压缩”">​</a></h3><p>Claude Code 有两种压缩触发方式：</p><p><strong>自动压缩</strong>：</p><p>当上下文使用率超过约 85-90% 时，Claude Code 会自动触发压缩。你会看到类似这样的提示：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Context usage is high. Compacting conversation to free up space...</span></span></code></pre></div><p>自动压缩的优点是<strong>不需要你操心</strong>，缺点是<strong>你不知道它保留了哪些信息、丢弃了哪些信息</strong>。它可能丢掉你认为关键的一个细节，也可能保留了大量你已经不需要的冗余。</p><p><strong>手动压缩</strong>：</p><p>你主动输入 <code>/compact</code> 或 <code>/compact [保留指令]</code>。手动压缩给你控制权，你可以精确指定保留范围。</p><p><strong>建议的策略</strong>：<strong>不要依赖自动压缩</strong>。自动压缩是安全网，不是工作流。你应该在以下时机主动手动压缩：</p><ul><li>完成一个主要阶段后（如重构方案确认完毕、准备开始执行）</li><li>观察到上下文膨胀症状出现时</li><li>对话超过 25 轮时（即使还没看到症状）</li><li>切换子任务前（如从&quot;分析问题&quot;切换到&quot;实现修复&quot;）</li></ul><h3 id="compact-的指令语法" tabindex="-1">/compact 的指令语法 <a class="header-anchor" href="#compact-的指令语法" aria-label="Permalink to “/compact 的指令语法”">​</a></h3><p><code>/compact</code> 支持附加指令来指定保留策略：</p><p><strong>基础用法</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/compact</span></span></code></pre></div><p>压缩对话，让 Claude 自行判断保留什么。</p><p><strong>指定保留主题</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/compact 只保留性能优化相关的对话内容，丢弃其他无关信息</span></span></code></pre></div><p><strong>指定保留的关键决策</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/compact 保留以下信息：</span></span>\n<span class="line"><span>1. 我们决定使用策略模式重构 orderService</span></span>\n<span class="line"><span>2. API 接口不能修改，保持向后兼容</span></span>\n<span class="line"><span>3. 测试用 Jest，覆盖率达到 80% 以上</span></span></code></pre></div><p><strong>指定丢弃的内容</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/compact 丢弃所有关于错误尝试的讨论，只保留最终的实现方案</span></span></code></pre></div><h3 id="压缩后恢复策略" tabindex="-1">压缩后恢复策略 <a class="header-anchor" href="#压缩后恢复策略" aria-label="Permalink to “压缩后恢复策略”">​</a></h3><p><code>/compact</code> 之后，Claude 通过一份摘要来&quot;回忆&quot;之前的对话。这份摘要的质量决定了压缩后 Claude 的表现。但摘要毕竟是摘要——它会丢失细节和细微的上下文。</p><p><strong>压缩后你应该做的</strong>：</p><ol><li><strong>快速浏览摘要</strong>：Claude 压缩后会展示保留的摘要。扫一眼，确认关键信息没有丢失</li><li><strong>补充遗漏</strong>：如果发现重要信息被丢弃了，立即补充：<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>压缩摘要中没有提到——我们之前还确认了错误处理使用 Result 模式，</span></span>\n<span class="line"><span>不要抛异常。请记住这一点。</span></span></code></pre></div></li><li><strong>重新锚定当前任务</strong>：简要重述你当前的进度和下一步方向：<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>回到重构——orderService.ts 的核心逻辑已经改完，</span></span>\n<span class="line"><span>现在继续处理 PaymentGateway 接口的兼容性验证。</span></span></code></pre></div></li><li><strong>确认 Claude 理解了</strong>：在继续之前，让 Claude 用一两句话确认它理解当前状态：<div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>先确认下你理解现在的进度。</span></span></code></pre></div></li></ol><p>这个恢复过程只需要 1-2 轮对话，但它能确保压缩后的对话质量不会断崖式下跌。</p><h3 id="compact-的局限性" tabindex="-1">/compact 的局限性 <a class="header-anchor" href="#compact-的局限性" aria-label="Permalink to “/compact 的局限性”">​</a></h3><p><code>/compact</code> 不是银弹，它有明确的局限：</p><ol><li><strong>丢失细微的上下文</strong>：你随口提的一句&quot;那个变量名我觉得还是叫 <code>userContext</code> 比较清楚&quot;——这种非结构化的偏好很可能会在压缩中被丢弃</li><li><strong>无法保留&quot;否定性信息&quot;</strong>：如果之前 Claude 提出了 A 方案被你否定，压缩后的摘要可能只写了&quot;采用 B 方案&quot;，而丢失了&quot;不要用 A 方案&quot;这个信息。在后续对话中，Claude 可能再次提出类似的 A 方案</li><li><strong>中间推理链断裂</strong>：如果一个 Bug 是经过 10 步推理定位到的，压缩只会保留&quot;定位结果：Bug 在 auth.ts 第 42 行&quot;，而不会保留完整的诊断推理链。如果修复后出现了新问题，Claude 需要重新推理</li><li><strong>无法区分&quot;重要&quot;和&quot;看起来重要&quot;</strong>：自动压缩的提取算法基于内容的重复频率和位置，而不是真正的语义重要性</li></ol><blockquote><p>缓解策略：对于复杂任务，在关键节点<strong>主动向 Claude 确认</strong>：&quot;总结一下目前达成的共识和已完成的步骤&quot;。这句话会以 Claude 的回复形式明确记录在对话中，压缩时被保留的概率远高于你的单方面指令。</p></blockquote><h2 id="_11-5-clear-清空对话" tabindex="-1">11.5 /clear 清空对话 <a class="header-anchor" href="#_11-5-clear-清空对话" aria-label="Permalink to “11.5 /clear 清空对话”">​</a></h2><p>如果说 <code>/compact</code> 是整理桌面，<code>/clear</code> 就是端走整张桌子，换一张新的。</p><h3 id="clear-与-compact-的本质区别" tabindex="-1">/clear 与 /compact 的本质区别 <a class="header-anchor" href="#clear-与-compact-的本质区别" aria-label="Permalink to “/clear 与 /compact 的本质区别”">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>/compact</th><th>/clear</th></tr></thead><tbody><tr><td><strong>保留什么</strong></td><td>压缩后的摘要 + 最近几轮对话</td><td>System Prompt + CLAUDE.md + Memory</td></tr><tr><td><strong>丢弃什么</strong></td><td>冗余的工具输出、中间过程</td><td><strong>一切对话历史</strong>，包括压缩摘要</td></tr><tr><td><strong>Claude 的状态</strong></td><td>&quot;记得&quot;关键信息</td><td>彻底失忆，从头开始</td></tr><tr><td><strong>适用场景</strong></td><td>同一任务太长，需要释放空间</td><td>话题完全切换，需要全新开始</td></tr><tr><td><strong>风险</strong></td><td>可能丢失细微信息</td><td>丢失所有当前任务的进度</td></tr><tr><td><strong>恢复成本</strong></td><td>低（1-2 轮对话恢复）</td><td>高（需要完整重述背景）</td></tr></tbody></table><h3 id="什么时候用-clear" tabindex="-1">什么时候用 /clear <a class="header-anchor" href="#什么时候用-clear" aria-label="Permalink to “什么时候用 /clear”">​</a></h3><p><code>/clear</code> 是重型武器，只在以下情况使用：</p><p><strong>场景一：话题完全切换</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>之前：调试 Webpack 配置问题，涉及 10 个配置文件的读写</span></span>\n<span class="line"><span>现在：想用 Claude 设计一个全新的 API 路由结构</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>→ /clear 后重新开始。</span></span>\n<span class="line"><span>两个任务完全无关，之前的上下文都是噪音。</span></span></code></pre></div><p><strong>场景二：上下文污染严重</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>之前的对话中，Claude 多次误解你的意思，形成了错误的认知惯性。</span></span>\n<span class="line"><span>你纠正了好几次，但它仍然在之前的错误理解上打转。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>→ /clear，用一个干净的上下文重新给出精确的指令。</span></span>\n<span class="line"><span>有时&quot;重启&quot;比&quot;修复&quot;更高效。</span></span></code></pre></div><p><strong>场景三：需要一个全新的视角</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你已经和 Claude 在同一个方案上讨论了很久，</span></span>\n<span class="line"><span>感觉思路被局限在某个方向。你想看看 Claude 能否提出完全不同的方案。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>→ /clear，用一个开放式的 Prompt 重新开始。</span></span>\n<span class="line"><span>旧的讨论方向不会束缚 Claude 的思路。</span></span></code></pre></div><p><strong>场景四：上下文已被系统压缩过多次</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>如果一次对话已经被自动压缩过 2-3 次，对话历史已经变成了</span></span>\n<span class="line"><span>&quot;摘要的摘要的摘要&quot;，信息丰富度已经很低。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>→ /clear 重新开始，重新建立上下文，质量更高。</span></span></code></pre></div><h3 id="执行-clear-之前" tabindex="-1">执行 /clear 之前 <a class="header-anchor" href="#执行-clear-之前" aria-label="Permalink to “执行 /clear 之前”">​</a></h3><p><code>/clear</code> 不可撤销。在执行之前，做好以下准备：</p><ol><li><p><strong>保存关键结论到其他地方</strong>：</p><ul><li>已经确认的技术方案 → 写进 CLAUDE.md 或项目文档</li><li>已经完成的代码 → 确保已经 commit</li><li>重要的决策和理由 → 记录在 commit message 或 issue 中</li></ul></li><li><p><strong>让 Claude 输出一份最终总结</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>在清空之前，帮我总结一下本次对话中达成的所有重要决策和已完成的工作。</span></span>\n<span class="line"><span>我会把这份总结保存下来。</span></span></code></pre></div><p>这份总结是你重新开始时向 Claude 提供背景的素材。</p></li><li><p><strong>确认当前所有改动已保存</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>确认一下，本次对话中做的所有代码改动都已经写入了文件。</span></span></code></pre></div><p>确保没有只在 Claude 的&quot;记忆&quot;中存在、尚未实际写入磁盘的修改。</p></li></ol><h3 id="clear-之后的快速重启" tabindex="-1">/clear 之后的快速重启 <a class="header-anchor" href="#clear-之后的快速重启" aria-label="Permalink to “/clear 之后的快速重启”">​</a></h3><p><code>/clear</code> 后，Claude 不知道你是谁、在做什么、之前讨论了什么。你需要高效地重新建立上下文：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>（/clear 后）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>我们之前在做 orderService 的重构，以下是关键背景：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>1. 目标：将订单查询逻辑从混杂的 if-else 改为策略模式</span></span>\n<span class="line"><span>2. 约束：不能修改 src/api/orderApi.ts 的接口签名</span></span>\n<span class="line"><span>3. 已完成：核心的策略接口和三个具体策略已实现</span></span>\n<span class="line"><span>4. 当前问题：PaymentGateway 接口的兼容性验证还没做</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>请先读取 src/services/orderService.ts 和相关文件，理解当前状态。</span></span></code></pre></div><p>这段&quot;重启提示&quot;包含了目标、约束、进度、下一步——信息密度极高，在一段话中重建了之前的核心上下文。</p><h2 id="_11-6-会话管理" tabindex="-1">11.6 会话管理 <a class="header-anchor" href="#_11-6-会话管理" aria-label="Permalink to “11.6 会话管理”">​</a></h2><p>除了在对话内部管理上下文，Claude Code 还提供了<strong>会话级别</strong>的管理能力——保存、恢复、查看历史会话。</p><h3 id="为什么要管理会话" tabindex="-1">为什么要管理会话 <a class="header-anchor" href="#为什么要管理会话" aria-label="Permalink to “为什么要管理会话”">​</a></h3><p>一个对话（Session）是一个独立的上下文空间。不同对话之间的上下文完全隔离。这意味着：</p><ul><li>在对话 A 中讨论的内容不会影响对话 B</li><li>对话 A 的上下文膨胀不会拖累对话 B</li><li>你可以为不同的任务维护不同的对话，各自保持&quot;干净&quot;的上下文</li></ul><h3 id="会话的创建与命名" tabindex="-1">会话的创建与命名 <a class="header-anchor" href="#会话的创建与命名" aria-label="Permalink to “会话的创建与命名”">​</a></h3><p><strong>创建新会话</strong>：</p><p>在 VSCode 侧边栏面板中，点击右上角的 <strong>加号（+）</strong> 图标即可创建新会话。也可以通过快捷键 <code>Cmd+N</code>（需在设置中启用 <code>enableNewConversationShortcut</code>）。</p><p><strong>命名会话</strong>：</p><p>Claude Code 默认以时间戳自动命名会话（如 &quot;Session 2026-05-30 14:23&quot;）。你应该<strong>立即重命名</strong>为有意义的名字。</p><p>好的命名：</p><ul><li><code>重构 orderService 策略模式</code></li><li><code>调试支付回调签名验证</code></li><li><code>编写用户模块单元测试</code></li><li><code>审查 PR #342</code></li></ul><p>不好的命名：</p><ul><li><code>Session 1</code></li><li><code>测试</code></li><li><code>问题</code></li><li><code>未命名</code></li></ul><p>命名是你未来在历史会话列表中快速定位的<strong>唯一线索</strong>。一个月后面对 50 个历史会话时，好的命名能帮你 3 秒找到需要的会话，不好的命名意味着你需要逐个打开查看内容。</p><h3 id="查看和恢复历史会话" tabindex="-1">查看和恢复历史会话 <a class="header-anchor" href="#查看和恢复历史会话" aria-label="Permalink to “查看和恢复历史会话”">​</a></h3><p>点击侧边栏面板的<strong>历史时钟图标</strong>，可以看到所有历史会话的列表。列表显示每个会话的：</p><ul><li>名称</li><li>最后活跃时间</li><li>消息数量</li></ul><p>点击任意历史会话即可<strong>恢复</strong>——你可以继续之前的对话，上下文（包括压缩后的摘要）完整保留。</p><blockquote><p>历史会话的上下文是持久化的。即使你关闭了 VSCode、重启了电脑，一个月后打开历史会话，Claude 仍然&quot;记得&quot;那个对话中发生过什么。</p></blockquote><h3 id="会话的归档" tabindex="-1">会话的归档 <a class="header-anchor" href="#会话的归档" aria-label="Permalink to “会话的归档”">​</a></h3><p>当你不再需要某个会话时，可以将其归档（Archive）。归档后的会话从主列表中隐藏，但不会被删除——你仍然可以在归档列表中找到并恢复。</p><p><strong>何时归档</strong>：</p><ul><li>任务已经完成，代码已合并</li><li>项目已经结束或不再维护</li><li>会话已经很久没有活动（&gt; 2 周）</li></ul><p>归档不是删除——它是&quot;整理&quot;。保持主列表的整洁，让你能快速找到当前活跃的会话。</p><h2 id="_11-7-多会话并存策略" tabindex="-1">11.7 多会话并存策略 <a class="header-anchor" href="#_11-7-多会话并存策略" aria-label="Permalink to “11.7 多会话并存策略”">​</a></h2><p>这是本章最重要的实践技巧之一。它不是 Claude Code 的某个具体功能，而是一种<strong>工作习惯</strong>。</p><h3 id="核心理念-一个会话-一个任务" tabindex="-1">核心理念：一个会话 = 一个任务 <a class="header-anchor" href="#核心理念-一个会话-一个任务" aria-label="Permalink to “核心理念：一个会话 = 一个任务”">​</a></h3><p>不要在同一个会话中混合处理多个不相关的任务。每个会话应该有<strong>单一的、明确的主题边界</strong>。</p><p><strong>反模式</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>会话 &quot;工作&quot;：</span></span>\n<span class="line"><span>  - 修复登录 Bug</span></span>\n<span class="line"><span>  - 优化首页加载性能</span></span>\n<span class="line"><span>  - 更新 README</span></span>\n<span class="line"><span>  - 审查同事的 PR</span></span>\n<span class="line"><span>  - 设计新的 API 路由</span></span></code></pre></div><p>这个会话的上下文是五个完全无关主题的大杂烩。Claude 在帮你优化首页性能时，登录 Bug 的调试历史还占着上下文窗口的大量空间。这些信息对当前任务不但没用，还会干扰 Claude 的判断。</p><p><strong>推荐模式</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>会话 1: &quot;修复登录 Token 刷新 Bug&quot;</span></span>\n<span class="line"><span>会话 2: &quot;优化首页 LCP 性能&quot;</span></span>\n<span class="line"><span>会话 3: &quot;更新项目 README 和 API 文档&quot;</span></span>\n<span class="line"><span>会话 4: &quot;审查 PR #342 - 支付模块&quot;</span></span>\n<span class="line"><span>会话 5: &quot;设计 v2 API 路由结构&quot;</span></span></code></pre></div><p>每个会话的上下文都是纯净的、与当前任务高度相关的。Claude 在&quot;优化首页性能&quot;的会话中，看到的全部内容都与性能优化相关。</p><h3 id="多会话的日常工作流" tabindex="-1">多会话的日常工作流 <a class="header-anchor" href="#多会话的日常工作流" aria-label="Permalink to “多会话的日常工作流”">​</a></h3><p>以下是一个典型一天中的多会话使用方式：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>早上 9:00 — 打开会话 &quot;修复登录 Token 刷新 Bug&quot;</span></span>\n<span class="line"><span>  │  继续昨天的工作，上下文完整保留</span></span>\n<span class="line"><span>  │  10:30 修复完成，提交 PR</span></span>\n<span class="line"><span>  │</span></span>\n<span class="line"><span>上午 10:35 — 收到同事请求，帮忙审查 PR #342</span></span>\n<span class="line"><span>  │  切换到会话 &quot;审查 PR #342 - 支付模块&quot;</span></span>\n<span class="line"><span>  │  上下文中没有登录 Bug 的任何信息，干净高效</span></span>\n<span class="line"><span>  │  11:20 审查完成，输出 Review 意见</span></span>\n<span class="line"><span>  │</span></span>\n<span class="line"><span>上午 11:25 — 回到会话 &quot;修复登录 Token 刷新 Bug&quot;</span></span>\n<span class="line"><span>  │  PR Review 反馈回来了，需要微调</span></span>\n<span class="line"><span>  │  上下文中仍然是登录模块的所有讨论，不需要任何恢复</span></span>\n<span class="line"><span>  │</span></span>\n<span class="line"><span>下午 14:00 — 新任务：优化首页性能</span></span>\n<span class="line"><span>  │  创建新会话 &quot;优化首页 LCP 性能&quot;</span></span>\n<span class="line"><span>  │  Claude 读取首页相关文件，进行性能分析</span></span>\n<span class="line"><span>  │  16:00 优化方案确定，开始实施</span></span></code></pre></div><p>注意这个流的关键优势：<strong>每次切换会话，你切换到的会话中的上下文是完整且纯净的</strong>。你不需要每次切换任务时执行 <code>/compact</code> 或 <code>/clear</code>——会话本身帮你隔离了上下文。</p><h3 id="会话切换的最佳实践" tabindex="-1">会话切换的最佳实践 <a class="header-anchor" href="#会话切换的最佳实践" aria-label="Permalink to “会话切换的最佳实践”">​</a></h3><ol><li><strong>为每个独立任务创建独立会话</strong>。任务完成后再归档</li><li><strong>不要在会话 A 中&quot;顺便&quot;处理会话 B 的任务</strong>。即使是&quot;帮我快速看一下这个&quot;——先切换到正确的会话或创建新会话</li><li><strong>利用 Claude Code 的多会话能力</strong>。VSCode 扩展支持同时打开多个会话（每个在独立的标签页中），你可以在它们之间快速切换</li><li><strong>命名要具体到能唯一识别任务</strong>。&quot;重构用户模块&quot;比&quot;重构&quot;好一百倍</li><li><strong>定期整理会话列表</strong>。每周花 2 分钟，归档已完成的会话，重命名那些当初随手起名的会话</li></ol><h3 id="多会话与-git-分支的配合" tabindex="-1">多会话与 Git 分支的配合 <a class="header-anchor" href="#多会话与-git-分支的配合" aria-label="Permalink to “多会话与 Git 分支的配合”">​</a></h3><p>多会话策略与 Git 分支工作流天然契合：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>分支: feature/login-token-fix    →  会话: &quot;修复登录 Token 刷新 Bug&quot;</span></span>\n<span class="line"><span>分支: perf/homepage-lcp          →  会话: &quot;优化首页 LCP 性能&quot;</span></span>\n<span class="line"><span>分支: docs/api-v2                →  会话: &quot;设计 v2 API 路由结构&quot;</span></span></code></pre></div><p>一个分支对应一个会话。切换分支时切换会话，上下文始终与当前代码状态保持同步。</p><h2 id="_11-8-上下文管理最佳实践" tabindex="-1">11.8 上下文管理最佳实践 <a class="header-anchor" href="#_11-8-上下文管理最佳实践" aria-label="Permalink to “11.8 上下文管理最佳实践”">​</a></h2><p>以下是经过大量实战验证的上下文管理方法。它们不是互相独立的技巧，而是一个有机的整体——同时实践效果最好。</p><h3 id="_1-一次一个主题" tabindex="-1">1. 一次一个主题 <a class="header-anchor" href="#_1-一次一个主题" aria-label="Permalink to “1. 一次一个主题”">​</a></h3><blockquote><p>不要在同一个会话中混合处理多个不相关的任务。</p></blockquote><p>这是上下文管理的<strong>第一原则</strong>。违反这一条，后续所有的管理技巧都只能亡羊补牢。</p><p>如果你正在会话中处理任务 A，临时被要求处理任务 B，正确的做法是：</p><ul><li>创建一个新会话来处理任务 B</li><li>完成任务 B 后回到原会话继续任务 A</li></ul><p>而不是在图省事在同一个会话中说：&quot;先不管 A 了，帮我看看 B 这个 Bug。&quot;</p><h3 id="_2-定期手动-compact" tabindex="-1">2. 定期手动 compact <a class="header-anchor" href="#_2-定期手动-compact" aria-label="Permalink to “2. 定期手动 compact”">​</a></h3><p>不要等待自动压缩。在以下节点主动执行 <code>/compact</code>：</p><ul><li>完成一个主要方案设计后</li><li>完成一个子任务后（如&quot;所有测试写完了&quot;）</li><li>对话超过 25 轮时</li><li>观察到任何上下文膨胀症状时</li></ul><p>养成在每个里程碑后 &quot;/compact + 快速确认摘要&quot; 的习惯。</p><h3 id="_3-压缩前先确认" tabindex="-1">3. 压缩前先确认 <a class="header-anchor" href="#_3-压缩前先确认" aria-label="Permalink to “3. 压缩前先确认”">​</a></h3><p>在执行 <code>/compact</code> 之前，花 30 秒想一下：</p><ul><li>这个对话中哪些信息是<strong>必须保留</strong>的？</li><li>有没有我之前纠正过的方向，不希望 Claude 再犯的？</li></ul><p>如果有关键信息需要保留，用 <code>/compact 保留...</code> 的语法明确指定。</p><h3 id="_4-clear-后重述关键信息" tabindex="-1">4. /clear 后重述关键信息 <a class="header-anchor" href="#_4-clear-后重述关键信息" aria-label="Permalink to “4. /clear 后重述关键信息”">​</a></h3><p><code>/clear</code> 之后，Claude 对你的项目和你当前的任务一无所知。你需要用一段精炼的&quot;重启提示&quot;重建上下文：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>简明扼要地告诉 Claude：</span></span>\n<span class="line"><span>1. 项目的性质和技术栈</span></span>\n<span class="line"><span>2. 当前任务的目标和约束</span></span>\n<span class="line"><span>3. 已经完成了什么</span></span>\n<span class="line"><span>4. 下一步要做什么</span></span></code></pre></div><p>这个习惯能将 <code>/clear</code> 后的恢复时间从 5-6 轮缩短到 1-2 轮。</p><h3 id="_5-长任务分拆为子任务" tabindex="-1">5. 长任务分拆为子任务 <a class="header-anchor" href="#_5-长任务分拆为子任务" aria-label="Permalink to “5. 长任务分拆为子任务”">​</a></h3><p>一个需要 100 轮对话才能完成的任务，拆成 4 个子任务，每个子任务在一个独立会话中完成：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>原任务: 重构整个订单系统</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>分拆后:</span></span>\n<span class="line"><span>子任务 1（会话 A）: 重构数据模型层 → 15 轮，完成后 /compact</span></span>\n<span class="line"><span>子任务 2（会话 B）: 重构业务逻辑层 → 25 轮，完成后 /compact</span></span>\n<span class="line"><span>子任务 3（会话 C）: 重构 API 接口层 → 20 轮，完成后 /compact</span></span>\n<span class="line"><span>子任务 4（会话 D）: 集成测试与兼容性验证 → 20 轮，完成后 /compact</span></span></code></pre></div><p>总轮数相同（80 轮），但每个会话的上下文都在 25 轮以内，质量远高于一个 80 轮不压缩的会话。</p><p>需要注意的是，子任务之间的信息传递需要通过<strong>代码状态</strong>（已 commit 的代码）和<strong>CLAUDE.md</strong>（记录架构决策），而不是依赖 Claude 的记忆。</p><h3 id="_6-利用-memory-系统" tabindex="-1">6. 利用 Memory 系统 <a class="header-anchor" href="#_6-利用-memory-系统" aria-label="Permalink to “6. 利用 Memory 系统”">​</a></h3><p>Memory 是你跨会话传递持久化信息的渠道。当你希望 Claude 在未来的所有会话中都记住某个信息时，明确告诉它记录下来：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>记住：这个项目使用 Result 模式处理错误，不要使用 try-catch 抛异常。</span></span></code></pre></div><p>或者：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>记住我的偏好：React 组件使用函数式声明，不用 class component。</span></span></code></pre></div><p>这些信息会存储在 <code>.claude/projects/&lt;path&gt;/memory/</code> 下，在每次新会话启动时自动加载。</p><p>但注意：Memory 应该用于<strong>稳定、长期</strong>的信息，而不是临时性的任务描述。&quot;我们正在重构订单模块&quot;这种临时状态不应该进 Memory——它只对当前任务有效。</p><h3 id="_7-监控上下文用量" tabindex="-1">7. 监控上下文用量 <a class="header-anchor" href="#_7-监控上下文用量" aria-label="Permalink to “7. 监控上下文用量”">​</a></h3><p>使用 <code>/context</code> 命令查看当前的上下文使用情况：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/context</span></span></code></pre></div><p>Claude Code 会显示当前上下文窗口的使用量、各组成部分的占比。定期检查这个数据，你能建立对上下文消耗速度的直观感觉。</p><p>一旦你建立了这种感觉，你就不再需要频繁查看——你会本能地在&quot;感觉上下文快要溢出了&quot;的时候执行 <code>/compact</code>。</p><h3 id="_8-先读再问" tabindex="-1">8. 先读再问 <a class="header-anchor" href="#_8-先读再问" aria-label="Permalink to “8. 先读再问”">​</a></h3><p>在提出一个复杂问题之前，先让 Claude 读取相关文件，而不是依赖它&quot;可能记得&quot;之前读过的内容。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 不好：</span></span>\n<span class="line"><span>Claude，我们之前讨论的那个 validator.ts 文件，你帮我加个 XX 验证。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># 好：</span></span>\n<span class="line"><span>先读取 src/utils/validator.ts，然后帮我加一个 XX 验证函数。</span></span></code></pre></div><p>&quot;先读再问&quot;确保 Claude 对文件内容的理解是基于<strong>最新内容</strong>，而不是基于可能已经被压缩或丢失的旧上下文。这个习惯在长对话中尤其重要——你无法确定 validator.ts 的内容是否仍然在上下文窗口中。</p><h3 id="_9-善用-claude-md" tabindex="-1">9. 善用 CLAUDE.md <a class="header-anchor" href="#_9-善用-claude-md" aria-label="Permalink to “9. 善用 CLAUDE.md”">​</a></h3><p>CLAUDE.md 是每次对话自动加载的，不占用对话历史的上下文配额（它是在对话开始前就被加载的，占用的是固定的初始开销）。因此，<strong>适合放在 CLAUDE.md 中的信息不要放在对话指令中反复重复</strong>。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 不要每次都说的信息 → 放进 CLAUDE.md</span></span>\n<span class="line"><span>- 项目的技术栈和架构</span></span>\n<span class="line"><span>- 编码规范和约定</span></span>\n<span class="line"><span>- 常用命令</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># 只在当前对话中说的信息 → 放在对话指令中</span></span>\n<span class="line"><span>- 当前任务的具体目标</span></span>\n<span class="line"><span>- 临时的约束条件</span></span>\n<span class="line"><span>- 特定于当前任务的偏好</span></span></code></pre></div><p>第 12 章将深入讨论 CLAUDE.md 的编写策略。</p><h3 id="实践清单" tabindex="-1">实践清单 <a class="header-anchor" href="#实践清单" aria-label="Permalink to “实践清单”">​</a></h3><p>你可以把以下清单作为日常上下文管理的检查项：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>□ 当前会话只处理一个主题吗？</span></span>\n<span class="line"><span>□ 对话超过 25 轮了吗？（如果是，考虑 /compact）</span></span>\n<span class="line"><span>□ 观察到任何上下文膨胀症状了吗？</span></span>\n<span class="line"><span>  □ Claude 忘记了早期指令？</span></span>\n<span class="line"><span>  □ Claude 在重复或绕圈子？</span></span>\n<span class="line"><span>  □ Claude 忽略了最近的细节？</span></span>\n<span class="line"><span>  □ 工具调用变得越来越不精准？</span></span>\n<span class="line"><span>□ 如果准备执行 /clear，关键结论已保存到其他地方了吗？</span></span>\n<span class="line"><span>□ 历史会话有清晰的名字吗？</span></span>\n<span class="line"><span>□ 已完成的会话归档了吗？</span></span>\n<span class="line"><span>□ Memory 中存储的信息都是长期有效的吗？</span></span></code></pre></div><h2 id="_11-9-本章小结" tabindex="-1">11.9 本章小结 <a class="header-anchor" href="#_11-9-本章小结" aria-label="Permalink to “11.9 本章小结”">​</a></h2><p>上下文管理不是 Claude Code 的一项&quot;高级功能&quot;——它是<strong>有效使用 Claude Code 的基础素养</strong>。同样的 Claude Code，在懂得管理上下文的开发者手中和在不懂得管理的开发者手中，产出的质量可以是天壤之别。</p><h3 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to “核心要点”">​</a></h3><ol><li><strong>上下文窗口是有限资源</strong>。每一条消息、每一次文件读取、每一个命令输出都在消耗它。你需要像管理内存一样管理上下文</li><li><strong>Token 消耗比你想的快</strong>。英文一个单词约 1.3 token，中文一个汉字约 1.5 token。中文用户需要更加注意上下文消耗</li><li><strong>上下文膨胀的症状很微妙</strong>。Claude 不会直接说&quot;我上下文不够了&quot;——它表现为忘记早期指令、重复自己、忽略细节、工具调用变模糊</li><li><strong>/compact 是日常工具，/clear 是重置按钮</strong>。前者用于释放空间同时保留关键信息，后者用于彻底的上下文切换。它们的适用场景完全不同</li><li><strong>多会话是上下文隔离的最强工具</strong>。一个会话一个任务——不是建议，是原则。违反这一条，后续所有的管理都只是修修补补</li><li><strong>压缩后必须恢复</strong>。/compact 之后花 1-2 轮对话确认摘要完整、补充遗漏、重新锚定任务方向——这个步骤不可省略</li><li><strong>上下文管理是从&quot;会用&quot;到&quot;用好&quot;的关键跨越</strong>。基础篇教的是&quot;怎么让 Claude 做事&quot;，本章教的是&quot;怎么让 Claude 持续做好事&quot;</li></ol><h3 id="与前后章节的关系" tabindex="-1">与前后章节的关系 <a class="header-anchor" href="#与前后章节的关系" aria-label="Permalink to “与前后章节的关系”">​</a></h3><ul><li><strong>第 10 章</strong>讲 Agent Loop——Claude <strong>怎么工作</strong>。本章讲上下文——Claude <strong>记得什么</strong>。理解 Agent Loop 能帮你预测 Claude 的行为，理解上下文能帮你预测 Claude 的<strong>行为质量</strong></li><li><strong>第 12 章</strong>讲 CLAUDE.md——它是上下文窗口中<strong>由你完全控制的</strong>部分。读完本章，你应该已经理解 CLAUDE.md 在上下文中扮演的角色，第 12 章将教你如何最大化它的价值</li><li><strong>第 31 章</strong>（效率优化策略）将回到上下文管理的话题，从方法论层面讨论上下文预算的规划和分配</li></ul><h3 id="一个思维转变" tabindex="-1">一个思维转变 <a class="header-anchor" href="#一个思维转变" aria-label="Permalink to “一个思维转变”">​</a></h3><p>很多开发者把 Claude Code 当作一个&quot;万能答题机&quot;——问什么答什么，答不好就再问一次。这种心态下，上下文管理变成了被动应付：溢出了就压缩，忘了就再提醒。</p><p>真正高效的用法是：<strong>把 Claude Code 当作一个会疲劳的同事</strong>。你会在同事刚上班、头脑清醒时让他处理最重要的事，会用简洁的方式沟通关键信息，会在午餐后提醒他上午讨论的重要结论。对 Claude Code 也是一样——你需要站在它的角度，思考它&quot;能看到什么&quot;、&quot;记得什么&quot;、&quot;需要知道什么&quot;。</p><p>这就是上下文管理的本质：不是管理 token 的数字，而是管理<strong>信息的可用性</strong>。</p>',246))])}]]);export{p as __pageData,r as default};
